import{_ as i,o as l,c as t,ae as e}from"./chunks/framework.EHGTsUvI.js";const u=JSON.parse('{"title":"AI 辅助重构与测试补齐：一套更稳的日常提效方法","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/daily-efficiency.md","filePath":"ai-tutorial/daily-efficiency.md"}'),s={name:"ai-tutorial/daily-efficiency.md"};function n(r,a,h,p,o,d){return l(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="ai-辅助重构与测试补齐-一套更稳的日常提效方法" tabindex="-1">AI 辅助重构与测试补齐：一套更稳的日常提效方法 <a class="header-anchor" href="#ai-辅助重构与测试补齐-一套更稳的日常提效方法" aria-label="Permalink to &quot;AI 辅助重构与测试补齐：一套更稳的日常提效方法&quot;">​</a></h1><blockquote><p>AI 在开发里最容易让人上头的一幕，是它一口气吐出几百行“像模像样”的修改建议。 也是在这一刻，最需要冷静。因为真实项目里，速度从来不是唯一目标。大家真正需要的，不是一个敢猛改的搭子，而是一个能在不放大风险的前提下，帮你更快理解旧代码、重构结构、补测试和收敛失败反馈的协作者。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>如何把 AI 用在理解旧代码、拆分重构、补测试这三类高价值工作上</li><li>为什么“一把梭重构”通常比手写更危险</li><li>如何把构建、测试和 Review 反馈变成 AI 的修正回路</li><li>一套适合日常开发的稳妥工作流</li></ul></div><h2 id="_1-为什么重构场景特别适合-ai" tabindex="-1">1. 为什么重构场景特别适合 AI <a class="header-anchor" href="#_1-为什么重构场景特别适合-ai" aria-label="Permalink to &quot;1. 为什么重构场景特别适合 AI&quot;">​</a></h2><p>重构难，不只是因为代码难写，而是因为它同时包含三种成本：</p><ul><li><strong>理解成本</strong>：先搞清楚现有逻辑到底在做什么</li><li><strong>变更成本</strong>：把结构改好但不改坏行为</li><li><strong>验证成本</strong>：确认没有引入回归</li></ul><p>AI 在这里最有价值的地方，不一定是直接改代码，而是帮你更快完成前两步的“信息整理”和“候选方案生成”。</p><p>尤其在下面这些场景里很有效：</p><ul><li>大方法拆分</li><li>条件分支梳理</li><li>调用链说明</li><li>补测试样例</li><li>根据失败日志做定向修正</li></ul><h2 id="_2-最危险的用法-一句-帮我重构得更优雅" tabindex="-1">2. 最危险的用法：一句“帮我重构得更优雅” <a class="header-anchor" href="#_2-最危险的用法-一句-帮我重构得更优雅" aria-label="Permalink to &quot;2. 最危险的用法：一句“帮我重构得更优雅”&quot;">​</a></h2><p>这类提示最大的问题，是把所有关键决策都留给了模型：</p><ul><li>到底改结构还是改行为</li><li>允许改多少文件</li><li>能不能引入新模式</li><li>要不要改公共接口</li></ul><p>结果往往是：</p><ul><li>代码“看起来更漂亮”，但行为漂了</li><li>引入过度设计</li><li>改动面超出你的审查能力</li></ul><p>更稳的做法不是让 AI “自由发挥”，而是把重构拆成多个受控阶段。</p><h2 id="_3-一套更稳的-ai-重构流程" tabindex="-1">3. 一套更稳的 AI 重构流程 <a class="header-anchor" href="#_3-一套更稳的-ai-重构流程" aria-label="Permalink to &quot;3. 一套更稳的 AI 重构流程&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;理解现状&quot;] --&gt; B[&quot;锁定边界&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;拆小改动&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;补测试 / 跑验证&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;根据反馈修正&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;提交审查&quot;]</span></span></code></pre></div><h3 id="_3-1-先让-ai-做-解释器-不是-改写器" tabindex="-1">3.1 先让 AI 做“解释器”，不是“改写器” <a class="header-anchor" href="#_3-1-先让-ai-做-解释器-不是-改写器" aria-label="Permalink to &quot;3.1 先让 AI 做“解释器”，不是“改写器”&quot;">​</a></h3><p>第一步建议只让模型解释现有逻辑：</p><ul><li>列出主流程</li><li>列出关键分支</li><li>标注外部依赖</li><li>指出复杂度高的位置</li></ul><p>这个阶段不要让它直接输出新代码。因为你还没确认它是否真正理解了现有行为。</p><h3 id="_3-2-再锁边界" tabindex="-1">3.2 再锁边界 <a class="header-anchor" href="#_3-2-再锁边界" aria-label="Permalink to &quot;3.2 再锁边界&quot;">​</a></h3><p>在动代码前，需要明确告诉模型：</p><ul><li>哪些外部接口不能变</li><li>哪些行为必须保持</li><li>本轮只允许改哪些文件</li><li>优先优化什么，不优化什么</li></ul><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请只重构方法内部结构，不修改 public 方法签名，不调整返回体字段，不新增框架依赖。</span></span>
<span class="line"><span>目标是减少嵌套分支，提高可读性。</span></span></code></pre></div><h3 id="_3-3-只做小步改动" tabindex="-1">3.3 只做小步改动 <a class="header-anchor" href="#_3-3-只做小步改动" aria-label="Permalink to &quot;3.3 只做小步改动&quot;">​</a></h3><p>对 AI 来说，“一次改完整个模块”通常比“完成一个小步改动”风险高很多。</p><p>更推荐的粒度是：</p><ul><li>先抽取一个私有方法</li><li>再拆一个条件分支</li><li>再统一一个重复校验</li><li>最后补测试</li></ul><p>这样每一步都可以单独审查和验证。</p><h2 id="_4-补测试-ai-的高收益区" tabindex="-1">4. 补测试：AI 的高收益区 <a class="header-anchor" href="#_4-补测试-ai-的高收益区" aria-label="Permalink to &quot;4. 补测试：AI 的高收益区&quot;">​</a></h2><p>很多团队在老系统里最大的阻力不是“不会改”，而是“没有保护网不敢改”。这正是 AI 很适合介入的区域。</p><h3 id="_4-1-先补什么测试" tabindex="-1">4.1 先补什么测试 <a class="header-anchor" href="#_4-1-先补什么测试" aria-label="Permalink to &quot;4.1 先补什么测试&quot;">​</a></h3><p>推荐顺序：</p><ol><li>主流程 Happy Path</li><li>明显分支和异常路径</li><li>已知线上问题对应路径</li><li>边界条件和历史 bug 回归测试</li></ol><p>不建议一开始就要求模型“把覆盖率做到很高”。先保护最重要路径，更符合实际收益。</p><h3 id="_4-2-给模型什么输入最有效" tabindex="-1">4.2 给模型什么输入最有效 <a class="header-anchor" href="#_4-2-给模型什么输入最有效" aria-label="Permalink to &quot;4.2 给模型什么输入最有效&quot;">​</a></h3><p>补测试时，下面这些信息非常有帮助：</p><ul><li>被测方法或类</li><li>关键依赖</li><li>期望行为</li><li>一两个典型输入输出</li><li>当前已有测试风格</li></ul><p>如果连团队常用测试框架、断言风格、Mock 方式都不告诉模型，它很容易生成“不符合项目习惯”的测试代码。</p><h2 id="_5-构建和测试反馈-才是-ai-真正的闭环" tabindex="-1">5. 构建和测试反馈，才是 AI 真正的闭环 <a class="header-anchor" href="#_5-构建和测试反馈-才是-ai-真正的闭环" aria-label="Permalink to &quot;5. 构建和测试反馈，才是 AI 真正的闭环&quot;">​</a></h2><p>AI 在开发流程里真正高效的地方，是“根据失败结果快速修正”。这比它第一次输出多完美更重要。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Dev as 开发者</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant AI as AI 助手</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Build as 构建/测试</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Dev-&gt;&gt;AI: 给出目标与约束</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    AI--&gt;&gt;Dev: 输出重构方案或测试代码</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Dev-&gt;&gt;Build: 运行构建/测试</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Build--&gt;&gt;Dev: 返回失败信息</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Dev-&gt;&gt;AI: 回喂关键错误与相关代码</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    AI--&gt;&gt;Dev: 定向修正建议</span></span></code></pre></div><h3 id="_5-1-什么反馈值得回喂" tabindex="-1">5.1 什么反馈值得回喂 <a class="header-anchor" href="#_5-1-什么反馈值得回喂" aria-label="Permalink to &quot;5.1 什么反馈值得回喂&quot;">​</a></h3><ul><li>编译错误</li><li>单测失败断言</li><li>Lint 报错</li><li>Code Review 指出的问题</li></ul><h3 id="_5-2-什么反馈不值得整段丢进去" tabindex="-1">5.2 什么反馈不值得整段丢进去 <a class="header-anchor" href="#_5-2-什么反馈不值得整段丢进去" aria-label="Permalink to &quot;5.2 什么反馈不值得整段丢进去&quot;">​</a></h3><ul><li>大量重复日志</li><li>与当前改动无关的历史失败</li><li>长篇构建输出里与当前类无关的噪声</li></ul><p>回喂时应尽量保留关键信息、压缩外围噪声。</p><h2 id="_6-一个实用的任务模板" tabindex="-1">6. 一个实用的任务模板 <a class="header-anchor" href="#_6-一个实用的任务模板" aria-label="Permalink to &quot;6. 一个实用的任务模板&quot;">​</a></h2><p>如果你要把 AI 用在重构与补测试，可以按下面的节奏：</p><table tabindex="0"><thead><tr><th>阶段</th><th>目标</th><th>AI 适合做什么</th></tr></thead><tbody><tr><td>摸底</td><td>理解现有实现</td><td>生成流程说明、分支梳理、依赖分析</td></tr><tr><td>设计</td><td>明确重构方式</td><td>比较方案、列出风险、给拆分计划</td></tr><tr><td>实施</td><td>小步提交改动</td><td>输出局部修改建议、补辅助方法</td></tr><tr><td>验证</td><td>建立保护网</td><td>补 Happy Path、补异常测试</td></tr><tr><td>修正</td><td>消除回归</td><td>根据构建/测试失败做定向修复</td></tr></tbody></table><p>这套流程的重点不是“让 AI 代替开发者”，而是把开发者最费时间的信息整理工作交给 AI，把判断和确认保留给人。</p><h2 id="_7-什么时候不该交给-ai" tabindex="-1">7. 什么时候不该交给 AI <a class="header-anchor" href="#_7-什么时候不该交给-ai" aria-label="Permalink to &quot;7. 什么时候不该交给 AI&quot;">​</a></h2><p>有些任务不适合第一时间交给 AI：</p><ul><li>你自己都还没理解业务目标</li><li>这次改动涉及核心算法正确性</li><li>缺乏足够的验收标准</li><li>一次改动会跨多个敏感模块</li></ul><p>这类场景里，先由人把边界画清楚，再让 AI 参与局部环节，通常更稳。</p><h2 id="_8-常见反模式" tabindex="-1">8. 常见反模式 <a class="header-anchor" href="#_8-常见反模式" aria-label="Permalink to &quot;8. 常见反模式&quot;">​</a></h2><h3 id="_8-1-一次性大改" tabindex="-1">8.1 一次性大改 <a class="header-anchor" href="#_8-1-一次性大改" aria-label="Permalink to &quot;8.1 一次性大改&quot;">​</a></h3><p>表面上省时间，实际上会让 Review 和回滚都变得困难。</p><h3 id="_8-2-只让-ai-改代码-不让-ai-先解释" tabindex="-1">8.2 只让 AI 改代码，不让 AI 先解释 <a class="header-anchor" href="#_8-2-只让-ai-改代码-不让-ai-先解释" aria-label="Permalink to &quot;8.2 只让 AI 改代码，不让 AI 先解释&quot;">​</a></h3><p>这样你无法判断它是否真正理解原逻辑。</p><h3 id="_8-3-把覆盖率当成唯一目标" tabindex="-1">8.3 把覆盖率当成唯一目标 <a class="header-anchor" href="#_8-3-把覆盖率当成唯一目标" aria-label="Permalink to &quot;8.3 把覆盖率当成唯一目标&quot;">​</a></h3><p>覆盖率高不等于保护网有效。关键路径和高风险路径更重要。</p><h3 id="_8-4-不把失败信息回喂" tabindex="-1">8.4 不把失败信息回喂 <a class="header-anchor" href="#_8-4-不把失败信息回喂" aria-label="Permalink to &quot;8.4 不把失败信息回喂&quot;">​</a></h3><p>没有反馈闭环，AI 就只能重复猜测。</p><h2 id="_9-一份可复用的检查清单" tabindex="-1">9. 一份可复用的检查清单 <a class="header-anchor" href="#_9-一份可复用的检查清单" aria-label="Permalink to &quot;9. 一份可复用的检查清单&quot;">​</a></h2><p>在用 AI 做重构前，最好确认下面这些问题：</p><ul><li>当前改动的行为边界是否明确</li><li>是否知道哪些接口不能动</li><li>是否有最基本的验证方式</li><li>是否准备好了先做小步改动</li><li>是否能把失败结果快速回喂给 AI</li></ul><p>如果这些都具备，AI 在重构和补测试中的收益通常会非常明显。</p><h2 id="_10-小结" tabindex="-1">10. 小结 <a class="header-anchor" href="#_10-小结" aria-label="Permalink to &quot;10. 小结&quot;">​</a></h2><p>AI 在日常开发提效里最稳的价值，并不是“替你写完整功能”，而是：</p><ul><li>更快理解旧代码</li><li>更快拆分改动</li><li>更快建立保护网</li><li>更快消化失败反馈</li></ul><p>当你把它放进一个小步、可验证、有反馈的流程里，AI 才更像一个可靠的工程协作者，而不是不受控的代码生成器。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://docs.github.com/en/copilot" target="_blank" rel="noreferrer">GitHub Copilot 文档</a></li><li><a href="https://docs.cursor.com/context/codebase-indexing" target="_blank" rel="noreferrer">Cursor: Codebase indexing</a></li><li><a href="https://www.jetbrains.com/help/ai-assistant/about-ai-assistant.html" target="_blank" rel="noreferrer">JetBrains AI Assistant 文档</a></li><li>延伸阅读：<a href="./context-prompting.html">代码库上下文工程</a></li></ul>`,76)])])}const k=i(s,[["render",n]]);export{u as __pageData,k as default};
